        <ArrowLeft className="h-3.5 w-3.5" />
        Explore
      </Link>

      {/* Event header */}
      <div>
        <div className="flex items-center gap-2">
          {display && (
            <ProviderIcon
              className="h-5 w-5 text-muted-foreground"
              icon={display.icon}
            />
